settings.custom_css:
@media (max-width: 768.98px) {
/* Page background — deliberately NOT using the "selector" placeholder here (which
   Elementor Pro's Custom CSS replaces with the widget's own scoped class): these are
   ANCESTORS of the widget (Woodmart's own page wrapper), so they stay unscoped to
   apply page-wide instead of just inside the widget. */
body {
	background: #F5F4FB !important;
}
.wd-content-area,
main.wd-content-layout,
.content-layout-wrapper {
	background: transparent !important;
	box-shadow: none !important;
}

/* Coupon box — now its own block (moved by wi-checkout.js to sit right before
   Pagamento), styled to match the other white rounded cards. */
selector .e-coupon-box {
	background: #FFFFFF;
	border: 1px solid #E4E1F3;
	border-radius: 16px;
	padding: 18px;
}

/* 3 blocks in this exact order: Produtos, Informações (seus dados), Pagamento.
   These are physically moved via JS (below) to be real direct children of
   .e-checkout__container, in the right order — NOT via display:contents, which
   broke Mercado Pago's own price/discount widget inside the payment boxes
   (it relies on normal box layout to render). Their old empty wrapper shells
   are just hidden here. */
selector .e-checkout__container {
	display: flex !important;
	flex-direction: column !important;
}
selector .checkout-order-review,
selector .e-checkout__column-end,
selector .e-checkout__column-inner {
	padding: 0 !important;
	margin: 0 !important;
}

/* only hide fields that are optional or already hard-fixed elsewhere:
   #billing_country_field (country is forced to Brazil elsewhere) and
   .hostinger-reach-optin (cosmetic opt-in). billing_persontype/billing_cnpj,
   order_comments/additional-fields, and shipping-fields moved to the
   universal (not-mobile-only) block below — these were content decisions,
   not mobile-specific cosmetic ones, and shouldn't have been screen-size-scoped.
   #billing_company_field used to be hidden here too, but that was a bug, not a
   content decision: woocommerce-extra-checkout-fields-for-brazil's PF/PJ toggle
   (frontend.js) reveals it via inline .show()/.hide() on #billing_persontype
   change, and this !important beat that inline style, so Nome da Empresa never
   appeared on mobile for Pessoa Jurídica even though CNPJ did. Removed from this
   list so the field can show/hide normally at any screen size. */
selector #billing_country_field,
selector .hostinger-reach-optin {
	display: none !important;
}

/* order review table -> card row layout */
selector .woocommerce-checkout-review-order-table thead {
	display: none;
}
selector .woocommerce-checkout-review-order-table,
selector .woocommerce-checkout-review-order-table tbody,
selector .woocommerce-checkout-review-order-table tfoot {
	border: none;
	background: none;
}
selector .woocommerce-checkout-review-order-table .cart_item {
	display: flex;
	align-items: center;
	gap: 14px;
	border: none;
	padding: 4px 0 14px;
}
selector .woocommerce-checkout-review-order-table .cart_item td {
	border: none;
	padding: 0;
}
selector .woocommerce-checkout-review-order-table .product-name {
	flex: 1;
	font-weight: 600;
	font-size: 14.5px;
}
selector .woocommerce-checkout-review-order-table .product-name .product-quantity {
	color: #6B6580;
	font-weight: 400;
	display: block;
	font-size: 12.5px;
}
selector .woocommerce-checkout-review-order-table .product-total {
	font-family: ui-monospace, "SFMono-Regular", Consolas, monospace;
	font-weight: 600;
	white-space: nowrap;
}
selector .woocommerce-checkout-review-order-table tfoot tr th,
selector .woocommerce-checkout-review-order-table tfoot tr td {
	border-top: 1px solid #E4E1F3;
	padding-top: 10px;
}
selector .woocommerce-checkout-review-order-table tfoot tr.order-total th,
selector .woocommerce-checkout-review-order-table tfoot tr.order-total td {
	font-size: 24px;
	font-weight: 700;
	font-family: Georgia, "Times New Roman", serif;
	border-top: none;
}

/* payment methods -> bordered cards */
selector ul.payment_methods {
	list-style: none;
	padding: 0;
	margin: 0;
	display: flex;
	flex-direction: column;
	gap: 8px;
}
selector ul.payment_methods li.wc_payment_method {
	border: 1px solid #E4E1F3;
	border-radius: 12px;
	padding: 12px;
	background: #FFFFFF;
}
selector ul.payment_methods li.wc_payment_method label {
	font-weight: 600;
	font-size: 13.5px;
}
selector ul.payment_methods li.wc_payment_method input[type="radio"] {
	accent-color: #6D3CF2;
	margin-right: 8px;
}
selector ul.payment_methods li.wc_payment_method .payment_box {
	margin-top: 10px;
	background: #F1EFFA;
	border-radius: 8px;
}

/* "Payment" section label — the widget has no built-in title text field for this
   section (unlike Billing Details / Order Summary), so it's added via ::before to
   match the same uppercase small-caps style used by the other two section titles. */
selector #payment.woocommerce-checkout-payment::before {
	content: "Método de pagamento";
	display: block;
	font-size: 12px;
	font-weight: 700;
	text-transform: uppercase;
	letter-spacing: 1px;
	color: #6B6580;
	margin-bottom: 12px;
}
}
@media (min-width: 769px) {
	selector .e-checkout__container {
		display: grid !important;
		grid-template-columns: minmax(280px, 1fr) minmax(360px, 1.4fr);
		/* auto (not 1fr) — each right-column row takes only the height its own
		   content needs (Produtos/Cupom/Pagamento are very different lengths);
		   1fr forced all three to equal thirds, stretching the short ones
		   (like Cupom) with empty space. */
		grid-template-rows: auto auto auto;
		grid-template-areas:
			"informacoes produtos"
			"informacoes cupom"
			"informacoes pagamento";
		/* Both columns match height (Informações spans all 3 rows, so it already
		   equals whatever the right column's total height adds up to) — 750px
		   is a FLOOR, not a cap: min-height lets the grid grow taller when
		   content needs more room, so nothing ever has to scroll. */
		align-items: start;
		min-height: 750px;
		gap: 14px 24px;
	}
	selector .e-checkout__column-start {
		grid-area: informacoes;
	}
	selector .e-checkout__order_review {
		grid-area: produtos;
	}
	selector .e-coupon-box {
		grid-area: cupom;
	}
	selector .e-checkout__order_review-2 {
		grid-area: pagamento;
	}
}
/* "Seus dados" card — matches the same background/border/radius/padding used
   for .e-checkout__order_review ("Produtos"). Was mobile-only before, so on
   desktop this whole column had no white card background at all. */
selector #customer_details > div.woocommerce-billing-fields {
	background: #FFFFFF;
	border: 1px solid #E4E1F3;
	border-radius: 16px;
	padding: 18px;
}

/* "Observações do pedido" and "Ship to a different address?" aren't in the
   mockup — removed at any screen size. */
selector .woocommerce-additional-fields,
selector .woocommerce-shipping-fields {
	display: none !important;
}

/* "PRODUTOS" heading removed, and the tfoot rows (Subtotal/Entrega/Desconto/
   Total) tightened up — this table wasn't reshaped for desktop yet (only the
   mobile-only block above touches it), so on wider screens it was still using
   WooCommerce's own roomy default spacing. */
selector h3#order_review_heading {
	display: none !important;
}
selector .woocommerce-checkout-review-order-table tr th,
selector .woocommerce-checkout-review-order-table tr td {
	padding: 0 !important;
}
selector .woocommerce-checkout-review-order-table tfoot tr th,
selector .woocommerce-checkout-review-order-table tfoot tr td {
	border-top: 1px solid #E4E1F3;
	padding-top: 4px !important;
	padding-bottom: 4px !important;
}

/* "Complemento" label is visually-hidden (.screen-reader-text) by default —
   that's why its input sat higher than "Número"'s, since Número has a real
   label pushing its box down and Complemento didn't. Un-hiding it restores
   the same label-then-input rhythm on both, so the boxes line up. */
selector #billing_address_2_field label.screen-reader-text {
	position: static !important;
	width: auto !important;
	height: auto !important;
	overflow: visible !important;
	clip: auto !important;
	clip-path: none !important;
	margin: 0 !important;
	display: block !important;
	font-size: 12px !important;
	color: #6B6580 !important;
}

/* Shipping method box (collapsed by wi-checkout.js down to a single clickable
   summary row; clicking it reveals the full radio list to change methods). */
selector .wi-shipping-box {
	border: 1px solid #E4E1F3;
	border-radius: 9px;
	background: #F1EFFA;
	overflow: hidden;
}
selector .wi-shipping-summary {
	display: none;
	align-items: center;
	justify-content: space-between;
	padding: 9px 10px;
	cursor: pointer;
	font-size: 13.5px;
	color: #221E32;
}
selector .wi-shipping-chevron {
	color: #6B6580;
	transform: rotate(90deg);
	font-size: 16px;
	line-height: 1;
}
selector .wi-shipping-box ul#shipping_method {
	list-style: none;
	margin: 0;
	padding: 6px 10px;
}
selector .wi-shipping-box ul#shipping_method li {
	padding: 6px 0;
}

/* Mercado Pago's Pix illustration (<pix-template>) renders bigger than the
   other payment boxes. It's a web component we don't control the markup of.
   A transform:scale + negative-margin trick was tried here first to shrink it,
   but scale doesn't shrink the element's actual layout box — only guessing at
   the negative margin to compensate is fragile without seeing it render, and
   it broke the layout. Sticking to purely additive changes instead: just
   trimming the outer padding, which can't cause overlap since it only removes
   whitespace, never repositions anything. */
selector .mp-checkout-pix-container {
	padding: 8px !important;
}
/* <terms-and-conditions> turns out to be light-DOM (its actual markup is
   directly visible/inspectable), so unlike <pix-template> it's safe to target
   its contents directly. */
selector .mp-checkout-pix-terms-and-conditions {
	padding: 22px !important;
}

/* Field pairs: Número+Complemento, Tipo de Pessoa+CPF, Cidade+Estado.
   display:inline-block (the previous approach) left an inconsistent gap between
   paired fields — a well-known CSS quirk where whitespace in the HTML between
   inline-block elements renders as a visible, hard-to-control gap. Real Flexbox
   on the field wrapper fixes this: an exact "gap" value, no stray whitespace
   artifacts, and every field's row width is explicit instead of implied. */
selector .woocommerce-billing-fields__field-wrapper {
	display: flex !important;
	flex-wrap: wrap !important;
	column-gap: 12px !important;
}
/* full-width fields: force their own row */
selector #billing_email_field,
selector #billing_postcode_field,
selector #billing_address_1_field,
selector #billing_neighborhood_field,
selector #billing_phone_field {
	flex: 0 0 100% !important;
	width: 100% !important;
}
/* paired fields: exactly half the row, minus half the gap each */
selector #billing_number_field,
selector #billing_address_2_field,
selector #billing_persontype_field,
selector #billing_cpf_field,
selector #billing_city_field,
selector #billing_state_field {
	flex: 0 0 calc(50% - 6px) !important;
	width: calc(50% - 6px) !important;
	box-sizing: border-box !important;
}
/* the <select> for Tipo de Pessoa doesn't get the same width/height treatment
   as <input> elements by default (browsers size <select> to its own content,
   not its wrapper) — force it and its wrapper span to fill the field exactly
   like every text input already does. */
selector #billing_persontype_field .woocommerce-input-wrapper,
selector #billing_persontype_field select,
selector #billing_cpf_field .woocommerce-input-wrapper,
selector #billing_cpf_field input {
	display: block !important;
	width: 100% !important;
	box-sizing: border-box !important;
}
selector #billing_persontype_field select {
	height: 42px !important;
}
selector #billing_cpf_field input {
	height: 34px !important;
}
